function participants(t){return[owner(t.teamAId)?.id,owner(t.teamBId)?.id]}function involved(t,a=me()){return participants(t).includes(a.id)||(a.role==='commissioner'&&a.teamId&&[t.teamAId,t.teamBId].includes(a.teamId))}
